import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2005年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2005年/核心总结.md","filePath":"01_letters/2005年/核心总结.md"}'),o={name:"01_letters/2005年/核心总结.md"};function r(u,a,n,h,s,d){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_2005年巴菲特致股东信核心总结" tabindex="-1">2005年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2005年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2005年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增加56亿美元，每股账面价值增长6.4%</li><li>41年复合增长率21.5%</li><li>卡特里娜飓风造成25亿美元保险损失</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h3><ol><li><strong>MedPro医疗防护公司</strong>：6月收购，106年历史的医疗责任保险公司</li><li><strong>Forest River</strong>：房车制造商，年销售额16亿美元</li><li><strong>美通社(Business Wire)</strong>：全球新闻稿发布公司</li><li><strong>Applied Underwriters</strong>：薪酬服务和工伤赔偿保险</li><li><strong>PacifiCorp</strong>（通过中美能源）：西部六州170万电力客户</li></ol><h3 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h3><ul><li>吉列并入宝洁，确认50亿美元资本收益</li><li>大幅增持富国银行</li><li>新建仓安海斯-布希和沃尔玛</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="好企业、不错企业、糟糕企业-框架" tabindex="-1">&quot;好企业、不错企业、糟糕企业&quot;框架 <a class="header-anchor" href="#好企业、不错企业、糟糕企业-框架" aria-label="Permalink to &quot;&quot;好企业、不错企业、糟糕企业&quot;框架&quot;">​</a></h3><p><strong>好企业（梦想企业）</strong>：</p><ul><li>See&#39;s糖果：1972年2500万买入，累计贡献13.5亿美元税前利润</li><li>特点：持久护城河、低资本需求、可预测盈利</li></ul><p><strong>不错企业</strong>：</p><ul><li>FlightSafety：需要大量再投资才能增长</li><li>大多数公司属于此类</li></ul><p><strong>糟糕企业</strong>：</p><ul><li>航空业：增长快但永无止境的资本需求</li><li>&quot;最糟糕的企业就是那种增长很快，需要大量资本才能实现增长，然后赚不到什么钱&quot;</li></ul><h3 id="护城河理论" tabindex="-1">护城河理论 <a class="header-anchor" href="#护城河理论" aria-label="Permalink to &quot;护城河理论&quot;">​</a></h3><ul><li>真正伟大的企业必须有持久的&quot;护城河&quot;</li><li>资本主义动力学保证竞争对手会不断攻击高回报企业</li><li>稳定行业里的长期竞争优势是关键</li></ul><h3 id="投资回报最大化" tabindex="-1">投资回报最大化 <a class="header-anchor" href="#投资回报最大化" aria-label="Permalink to &quot;投资回报最大化&quot;">​</a></h3><ul><li>批评&quot;帮手&quot;如何侵蚀投资者回报</li><li>摩擦成本（佣金、管理费、顾问费）可能占企业收益的20%</li><li>&quot;对于投资者整体来说，回报随着运动的增加而减少&quot;</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><ul><li>浮存金493亿美元，零成本（尽管飓风损失34亿美元）</li><li>GEICO生产率两年提升32%，保单增长26%同时员工减少4%</li><li>保险是伯克希尔的基石</li></ul><h2 id="管理理念" tabindex="-1">管理理念 <a class="header-anchor" href="#管理理念" aria-label="Permalink to &quot;管理理念&quot;">​</a></h2><h3 id="继任计划" tabindex="-1">继任计划 <a class="header-anchor" href="#继任计划" aria-label="Permalink to &quot;继任计划&quot;">​</a></h3><ul><li>三位CEO候选人已确定</li><li>投资继任人计划正在执行，寻找年轻有潜力的投资经理</li></ul><h3 id="薪酬哲学" tabindex="-1">薪酬哲学 <a class="header-anchor" href="#薪酬哲学" aria-label="Permalink to &quot;薪酬哲学&quot;">​</a></h3><ul><li>批评CEO薪酬与业绩脱节</li><li>固定价格期权鼓励CEO扣留股息损害股东利益</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;真正伟大的企业必须有持久的&#39;护城河&#39;，保护投入资本获得高额回报。&quot;</p></blockquote><blockquote><p>&quot;退潮才知道谁在裸泳。&quot;</p></blockquote><blockquote><p>&quot;投资策略中潜伏的某些危险无法通过金融机构今天常用的模型发现。性情也很重要。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',33)])])}const b=l(o,[["render",r]]);export{c as __pageData,b as default};
